let _allStandings=[],_allDrivers=[],_userFavorites=[];async function initDriversPage(){initTabs(document.getElementById("tabs-root")),initFilters(),await loadDriversData(SeasonState.get()),window.addEventListener("seasonChanged",({detail:t})=>loadDriversData(t.year))}async function loadDriversData(t){await Promise.allSettled([loadStandings(t),loadAllDrivers(t),loadFavoriteIds()])}async function loadFavoriteIds(){if(AuthState.isLoggedIn())try{const t=await Favorites.list();_userFavorites=(t||[]).filter(t=>t.driver_id).map(t=>t.driver_id)}catch(t){_userFavorites=[]}else _userFavorites=[]}async function loadStandings(t){const e=document.getElementById("standings-table-wrap"),n=document.getElementById("podium-container");showLoading(e),n&&showLoading(n);try{if(_allStandings=await Standings.drivers(t),!_allStandings?.length)return showEmpty(e,"Нет данных","Таблица ещё не сформирована"),void(n&&(n.innerHTML=""));n&&renderStandingsPodium(n,_allStandings.slice(0,3)),renderTopDriversChart("chart-drivers-pts",_allStandings.slice(0,10)),renderPodiumsChart("chart-podiums",_allStandings),renderStandingsTable(e,_allStandings)}catch(t){showError(e,t.message)}}function renderStandingsPodium(t,e){const n=["p1","p2","p3"],a=[e[1],e[0],e[2]].filter(Boolean);t.innerHTML=`\n    <div class="podium-row">\n      ${a.map(t=>{const e=t.position,a=n[e-1]||"",i=getDriverName(t,"—"),r=t.driver?.photo_url||"",s=getConstructorName(t,"—");return`\n          <div class="podium-card ${a}">\n            <div class="podium-rank">${e}</div>\n            ${r?`<img src="${escapeHtml(r)}" alt="${escapeHtml(i)}" class="podium-photo" onerror="this.style.display='none'">`:`<div class="podium-photo" style="display:flex;align-items:center;justify-content:center;background:var(--bg-graphite);font-family:var(--font-display);font-weight:700;font-size:1.4rem;color:var(--teal);">${i.charAt(0)}</div>`}\n            <div class="podium-name">${escapeHtml(i)}</div>\n            <div class="podium-team">${escapeHtml(s)}</div>\n            <div class="podium-points">${t.points} <span>очков</span></div>\n          </div>\n        `}).join("")}\n    </div>\n  `}function renderStandingsTable(t,e){const n=t=>_userFavorites.includes(t);t.innerHTML=`\n    <table id="standings-table">\n      <thead>\n        <tr>\n          <th style="width:48px;">Место</th>\n          <th style="width:24px;"></th>\n          <th data-sort="name">Гонщик</th>\n          <th>Команда</th>\n          <th data-sort="points" class="text-right">Очки</th>\n          <th data-sort="wins"   class="text-right">Победы</th>\n          <th data-sort="podiums" class="text-right">Подиумы</th>\n          <th data-sort="starts" class="text-right">Старты</th>\n          <th class="text-right">DNF</th>\n          <th style="width:48px;"></th>\n        </tr>\n      </thead>\n      <tbody>\n        ${e.map(t=>{const e=t.position,a=t.previous_position,i=t.driver_id,r=getDriverName(t,"—"),s=getConstructorName(t,"—"),d=t.driver?.photo_url||"";t.best_result;return`\n            <tr class="${getRowHighlight(e)}">\n              <td class="table-position">\n                <span class="${getPositionClass(e)}">${e}</span>\n                ${getPosChangeHtml(e,a)}\n              </td>\n              <td>${d?`<img src="${escapeHtml(d)}" class="driver-avatar driver-avatar-sm" alt="" onerror="this.style.display='none'">`:""}</td>\n              <td>\n                <div class="driver-cell" style="gap:8px;">\n                  <div>\n                    <div class="driver-name">${escapeHtml(r)}</div>\n                    ${t.driver?.nationality?`<div class="driver-number">${escapeHtml(t.driver.nationality)}</div>`:""}\n                  </div>\n                </div>\n              </td>\n              <td class="muted">${escapeHtml(s)}</td>\n              <td class="text-right number" data-col="points" data-value="${t.points}"><strong style="color:var(--teal)">${t.points}</strong></td>\n              <td class="text-right number" data-col="wins"    data-value="${t.wins||0}">${t.wins||0}</td>\n              <td class="text-right number" data-col="podiums" data-value="${t.podiums||0}">${t.podiums||0}</td>\n              <td class="text-right muted"  data-col="starts"  data-value="${t.starts||0}">${t.starts||0}</td>\n              <td class="text-right muted">${t.dnfs||0}</td>\n              <td>\n                <div style="display:flex;gap:6px;justify-content:flex-end;">\n                  <a href="/driver-detail.html?id=${i}" class="btn btn-ghost btn-sm btn-icon" title="Страница гонщика">→</a>\n                  ${AuthState.isLoggedIn()?`<button class="btn-favorite ${n(i)?"active":""}" onclick="toggleFavoriteDriver(${i}, this)" title="${n(i)?"В избранном":"Добавить"}">★</button>`:""}\n                </div>\n              </td>\n            </tr>\n          `}).join("")}\n      </tbody>\n    </table>\n  `,initSortableTable(document.getElementById("standings-table"))}async function loadAllDrivers(t){const e=document.getElementById("drivers-table-wrap");showLoading(e);try{_allDrivers=await Drivers.list(t),renderDriversTable(_allDrivers),populateTeamFilter(_allDrivers)}catch(t){showError(e,t.message)}}function renderDriversTable(t){const e=document.getElementById("drivers-table-wrap");if(!t?.length)return void showEmpty(e,"Гонщики не найдены","Попробуйте изменить фильтры");e.innerHTML=`\n    <table id="drivers-table">\n      <thead>\n        <tr>\n          <th style="width:40px;">#</th>\n          <th data-sort="name">Гонщик</th>\n          <th>Национальность</th>\n          <th>Команда</th>\n          <th>Статус</th>\n          <th style="width:80px;"></th>\n        </tr>\n      </thead>\n      <tbody>\n        ${t.map((t,e)=>{const n=getDriverName(t,"—"),a=t.photo_url||"",i=getConstructorName(t,"—");return`\n            <tr>\n              <td class="muted">${t.driver_number||e+1}</td>\n              <td>\n                <div class="driver-cell">\n                  ${a?`<img src="${escapeHtml(a)}" class="driver-avatar" alt="${escapeHtml(n)}" onerror="this.style.display='none'">`:`<div class="driver-avatar" style="display:flex;align-items:center;justify-content:center;background:var(--bg-graphite);font-family:var(--font-display);font-weight:700;color:var(--teal);">${n.charAt(0)}</div>`}\n                  <div>\n                    <div class="driver-name">${escapeHtml(n)}</div>\n                    ${t.date_of_birth?`<div class="driver-number">р. ${formatDateShort(t.date_of_birth)}</div>`:""}\n                  </div>\n                </div>\n              </td>\n              <td data-col="name" data-value="${escapeHtml(n)}">${escapeHtml(t.nationality||"—")}</td>\n              <td class="muted">${escapeHtml(i)}</td>\n              <td>${getDriverStatusBadge(t.status)}</td>\n              <td>\n                <div style="display:flex;gap:6px;justify-content:flex-end;">\n                  <a href="/driver-detail.html?id=${t.id}" class="btn btn-ghost btn-sm btn-icon">→</a>\n                  ${AuthState.isLoggedIn()?`<button class="btn-favorite ${r=t.id,_userFavorites.includes(r)?"active":""}" onclick="toggleFavoriteDriver(${t.id}, this)">★</button>`:""}\n                </div>\n              </td>\n            </tr>\n          `;var r}).join("")}\n      </tbody>\n    </table>\n  `,initSortableTable(document.getElementById("drivers-table"))}function populateTeamFilter(t){const e=document.getElementById("filter-team");if(!e)return;const n=[...new Set(t.map(t=>getConstructorName(t,"")).filter(Boolean))].sort();e.innerHTML='<option value="">Все команды</option>'+n.map(t=>`<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`).join("")}function applyDriverFilters(){const t=document.getElementById("search-driver")?.value.toLowerCase()||"",e=document.getElementById("filter-team")?.value||"",n=document.getElementById("filter-status")?.value||"";renderDriversTable(_allDrivers.filter(a=>{const i=getDriverName(a,"").toLowerCase();if(t&&!i.includes(t))return!1;if(e){if(getConstructorName(a,"")!==e)return!1}return!n||a.status===n}))}function initFilters(){["search-driver","filter-team","filter-status"].forEach(t=>{document.getElementById(t)?.addEventListener("input",applyDriverFilters),document.getElementById(t)?.addEventListener("change",applyDriverFilters)})}document.addEventListener("DOMContentLoaded",initDriversPage);